mapper.select:
SELECT SK_KEYWORD, COUNT(*) SK_SIZE 
FROM t_search_keyword 
GROUP BY SK_KEYWORD
HAVING SK_SIZE > #{minCount}
ORDER BY SK_SIZE DESC
LIMIT	#{KeywordSize}

