mapper.sql:
SELECT * FROM ( SELECT SK_KEYWORD , COUNT(*) SK_SIZE FROM t_search_keyword WHERE 1=1
AND DATE_FORMAT(SK_REGDT,'%Y-%m-%d') >= #{searchBeginDate}
AND DATE_FORMAT(SK_REGDT,'%Y-%m-%d') <= #{searchEndDate}
GROUP BY SK_KEYWORD ORDER BY SK_SIZE DESC ) BODY ORDER BY SK_KEYWORD DESC
